import{_ as e,o as r,c as o,ag as d}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/gene-looper.png",h=JSON.parse('{"title":"Gene Looper","description":"","frontmatter":{},"headers":[],"relativePath":"modules/gene-looper.md","filePath":"modules/gene-looper.md"}'),n={name:"modules/gene-looper.md"};function a(i,t,g,l,p,u){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="gene-looper" tabindex="-1">Gene Looper <a class="header-anchor" href="#gene-looper" aria-label="Permalink to &quot;Gene Looper&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>Records up to 8 seconds of stereo audio into PSRAM then divides it into equal-length genes. 4 independent recording slots with per-slot organize, varispeed, mix, and overlap controls. Bank 1 pots control organize per slot, Bank 2 pots control varispeed per slot. Mix and overlap available as CV inputs.</p><img src="'+s+'" alt="gene-looper module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>gene1</strong></td><td>Slot 1 gene selection 0-1.</td></tr><tr><td><strong>gene2</strong></td><td>Slot 2 gene selection 0-1.</td></tr><tr><td><strong>gene3</strong></td><td>Slot 3 gene selection 0-1.</td></tr><tr><td><strong>gene4</strong></td><td>Slot 4 gene selection 0-1.</td></tr><tr><td><strong>speed1</strong></td><td>Slot 1 varispeed 0-1 (0.5=unity).</td></tr><tr><td><strong>speed2</strong></td><td>Slot 2 varispeed.</td></tr><tr><td><strong>speed3</strong></td><td>Slot 3 varispeed.</td></tr><tr><td><strong>speed4</strong></td><td>Slot 4 varispeed.</td></tr><tr><td><strong>mix1</strong></td><td>Slot 1 dry/wet 0-1.</td></tr><tr><td><strong>mix2</strong></td><td>Slot 2 dry/wet.</td></tr><tr><td><strong>mix3</strong></td><td>Slot 3 dry/wet.</td></tr><tr><td><strong>mix4</strong></td><td>Slot 4 dry/wet.</td></tr><tr><td><strong>overlap1</strong></td><td>Slot 1 gene crossfade 0-1.</td></tr><tr><td><strong>overlap2</strong></td><td>Slot 2 crossfade.</td></tr><tr><td><strong>overlap3</strong></td><td>Slot 3 crossfade.</td></tr><tr><td><strong>overlap4</strong></td><td>Slot 4 crossfade.</td></tr><tr><td><strong>record</strong></td><td>Record trigger (rising edge toggles).</td></tr><tr><td><strong>genes</strong></td><td>Gene count trigger (rising edge cycles 2/4/8/16).</td></tr><tr><td><strong>gl_reverse</strong></td><td>Reverse trigger (rising edge toggles).</td></tr><tr><td><strong>slot_select</strong></td><td>Slot select CV 0-1 (maps to slots 1-4).</td></tr><tr><td><strong>pan</strong></td><td>Stereo pan position. -1=left, 0=centre, +1=right.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left audio output.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right audio output.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Record a short phrase, set gene_count to 8, sweep Organize to scrub through fragments. Low Varispeed with high feedback in Matrix2x2 creates pitched-down drones. Reverse on a percussive hit gives backwards attacks. Modulate Pan with a slow LFO to widen the stereo image.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(n,[["render",a]]);export{h as __pageData,m as default};
